import sys, re
text = open(sys.argv[1]).read()
blocks = re.findall(r'```mermaid\n(.*?)```', text, re.DOTALL)
print(f"blocks found: {len(blocks)}")
bad = []
for i, b in enumerate(blocks, 1):
    for ln, line in enumerate(b.splitlines(), 1):
        s = line.strip()
        if not s: continue
        # skip classDef / class / classdef lines and subgraph title lines are checked too
        # We look for breaking chars inside [] or || label segments
        # Extract bracket labels
        for m in re.findall(r'\[\[?\(?(.*?)\)?\]?\]', s):
            if re.search(r'[():;/"<>{}|]', m):
                bad.append((i, ln, "NODE", m, s))
        # Extract edge pipe labels |"..."|
        for m in re.findall(r'\|"(.*?)"\|', s):
            if re.search(r'[():;/<>{}]', m):
                bad.append((i, ln, "EDGE", m, s))
if not bad:
    print("CLEAN: no breaking chars found in node/edge labels")
else:
    for blk, ln, kind, lbl, src in bad:
        print(f"block {blk} line {ln} [{kind}] label={lbl!r}  src={src!r}")
PY
